using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<ModelTrainingService> _logger;

    public ModelTrainingService(ILogger<ModelTrainingService> logger)
    {
        _dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        _modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        _logger = logger;
    }

    public string ModelPath => _modelPath;

    public void TrainAndEvaluate()
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = mlContext.Transforms.Text
            .FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
            .Append(mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        // Cross-validate to get metrics on this small dataset
        var cvResults = mlContext.MulticlassClassification
            .CrossValidate(data, pipeline, numberOfFolds: 3);

        _logger.LogInformation("=== Cross-Validation Metrics (3-fold) ===");
        foreach (var (result, i) in cvResults.Select((r, i) => (r, i)))
        {
            _logger.LogInformation(
                "Fold {Fold}: MicroAccuracy={Micro:F4}, MacroAccuracy={Macro:F4}, LogLoss={LogLoss:F4}",
                i + 1,
                result.Metrics.MicroAccuracy,
                result.Metrics.MacroAccuracy,
                result.Metrics.LogLoss);
        }

        double avgMicro = cvResults.Average(r => r.Metrics.MicroAccuracy);
        double avgMacro = cvResults.Average(r => r.Metrics.MacroAccuracy);
        double avgLogLoss = cvResults.Average(r => r.Metrics.LogLoss);
        _logger.LogInformation(
            "Average: MicroAccuracy={Micro:F4}, MacroAccuracy={Macro:F4}, LogLoss={LogLoss:F4}",
            avgMicro, avgMacro, avgLogLoss);

        // Train final model on all data and save
        ITransformer model = pipeline.Fit(data);
        mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _pool;

    public TicketClassifierController(
        PredictionEnginePool<TicketInput, TicketPrediction> pool)
    {
        _pool = pool;
    }

    [HttpPost("classify")]
    public ActionResult<object> Classify([FromBody] TicketRequest request)
    {
        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _pool.Predict(input);

        string[] labels = ["Billing", "General", "Technical"];
        var confidences = labels
            .Zip(prediction.Score, (label, score) => new { label, score })
            .OrderByDescending(x => x.score)
            .ToDictionary(x => x.label, x => Math.Round(x.score, 4));

        return Ok(new
        {
            predictedCategory = prediction.Category,
            confidences
        });
    }
}

